import Card from "@material-ui/core/Card";
import CardActions from "@material-ui/core/CardActions";
import CardContent from "@material-ui/core/CardContent";
import CardMedia from "@material-ui/core/CardMedia";
import Button from "@material-ui/core/Button";
import myImg from "./srija.jpg";
import { useNavigate } from "react-router-dom";
import { Box, Divider, Grid, Typography } from "@material-ui/core";

import React, { useEffect, useState } from "react";
import image1 from "./assets/1.jpg";
import image2 from "./assets/2.jpg"
import image3 from "./assets/3.jpg";
import obama from "./assets/intro.jpeg";
import image4 from "./assets/4.jpg";
import image5 from "./assets/5.jpg";
import image6 from "./assets/6.jpg";
import image9 from "./assets/9.jpg";
import image7 from "./assets/7.jpg";
import image21 from "./assets/21.jpg";
import image8 from "./assets/8.jpg";
import intromeme from "./assets/intromeme.jpeg";
import image22 from "./assets/22.jpeg";

const About = () => {
  const navigate = useNavigate();
  let pixel = 0;

  const [mousePos, setMousePos] = useState({});
  const [hover1, setHover1] = useState(false);
  const [hover2, setHover2] = useState(false);
  const handleArt = () => {
    navigate("/art");
  };
  const handleProjects = () => {
    navigate("/projects");
  };
  useEffect(() => {
    const handleMouseMove = (event) => {
      setMousePos({ x: event.clientX, y: event.clientY });
    };

    window.addEventListener("mousemove", handleMouseMove);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
    };
  }, []);
  if (parseInt(mousePos.x) <= 1062) {
    pixel = 1065 - parseInt(mousePos.x);
  } else {
    pixel = parseInt(mousePos.x) - 763;
  }
  const styles = {
    width: hover1 ? `calc(70% + ${pixel}px)` : "70%",
    // background: "#CFA294",
    background: "#EFEFEF",
    height: "150px",
    left: 0,
    position: "absolute",
    zIndex: hover1 ? 3 : 1,
    transition: "1000ms",
    maxWidth: "100%",
    borderRadius: "0px 10px 10px 0px",
  };
  const styles1 = {
    width: hover2 ? `calc(70% + ${pixel}px)` : "70%",
    // background: "#A64E4D",
    background: "#EFEFEF",
    // height: "150px",
    overflowX: "hidden",
    // textAlign: "center",
    // marginTop: "-320px",
    right: 0,
    position: "absolute",
    zIndex: hover2 ? 3 : 1,
    maxWidth: "100%",
    transition: "1000ms",
    borderRadius: "10px 0px 0px 10px",
  };
  return (
    <React.Fragment>
      <div className="App">
        <div
          style={{
            height: "300px",
            width: "900px",
            display: "flex",
            alignItems: "center",
            flexDirection: "row",
            margin: "0 auto",
          }}
        >
          <span>
            <img src={obama}></img>
          </span>
          <span
            style={{
              color: "#888",
              fontSize: "25px",
              fontWeight: "lighter",
              textAlign: "left",
              marginLeft: "40px",
            }}
          >
            A recent graduate with an Integrated Master of Technology in
            Computer Science from University of Hyderabad. I've enjoyed
            understanding complex hmmmm. When I'm not working you'll find me
            binge watching or painting.
          </span>
        </div>

        <div
          className="firstbox"
          onMouseEnter={() => {
            setHover1(true);
            // setProjects(true);
            // setArts(false);
          }}
          onMouseLeave={() => {
            setHover1(false);
            // setProjects(false);
          }}
          onClick={() => {
            handleProjects();
          }}
          style={{
            width: "100%",
            height: "150px",
            background: "white",
            display: "flex",
            flexDirection: "row-reverse",
            overflow: "hidden",
          }}
        >
          <div className="heading" style={styles}>
            <div
              style={{
                display: "flex",
                float: "right",
                padding: "20px",
                // width: "200px",
                // height: "200px",
              }}
            >
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  opacity: 0.6,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
                }}
                src={image21}
              />
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  opacity: 0.6,

                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
                }}
                src={image21}
              />
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  opacity: 0.6,

                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
                }}
                src={image21}
              />
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  opacity: 0.6,

                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
                }}
                src={image21}
              />
            </div>
          </div>
          <div className="projects" style={{ color: "black", width: "30%" }}>
            <span
              style={{
                fontSize: "60px",
                color: "#888888",
                textTransform: "uppercase",
              }}
            >
              Projects
            </span>
          </div>
        </div>
        <div
          className="secondbox"
          onMouseEnter={() => {
            setHover2(true);
            // setArts(true);
            // setProjects(false);
          }}
          onMouseLeave={() => {
            setHover2(false);
            // setArts(false);
          }}
          onClick={() => {
            handleArt();
          }}
          style={{
            width: "100%",

            // marginTop: "100px",
            height: "150px",
            background: "white",
            display: "flex",
            flexDirection: "row",
            marginTop: "10px",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              fontSize: "60px",
              color: "#888888",
              textTransform: "uppercase",
              // marginBlock: "auto",
              margin: "auto",
            }}
          >
            Art
          </div>
          <div
            style={{
              width: "80%",
              color: "black",
              margin: "auto",
              height: "-webkit-fill-available",
            }}
          >
            <div style={styles1}>
              <div
                style={{
                  display: "flex",
                  padding: "20px",
                }}
              >
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    opacity: 0.6,

                    // backgroundColor: "black",
                    objectFit: "cover",
                    "&:hover": {
                      backgroundColor: "orange",
                      opacity: [0.9, 0.8, 0.7],
                    },
                  }}
                  src={image5}
                />
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    opacity: 0.6,

                    // backgroundColor: "black",
                    objectFit: "cover",
                  }}
                  src={image6}
                />
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    opacity: 0.6,

                    // backgroundColor: "black",
                    objectFit: "cover",
                  }}
                  src={image7}
                />
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    opacity: 0.6,

                    objectFit: "cover",
                  }}
                  src={image8}
                />
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    opacity: 0.6,

                    objectFit: "cover",
                  }}
                  src={image1}
                />
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    objectFit: "cover",
                    opacity: 0.6,
                  }}
                  src={image2}
                />
                <Box
                  component="img"
                  sx={{
                    width: 200,
                    height: 110,
                    marginRight: 10,
                    opacity: 0.6,

                    // backgroundColor: "black",
                    objectFit: "cover",
                    "&:hover": {
                      backgroundColor: "orange",
                      opacity: [0.9, 0.8, 0.7],
                    },
                  }}
                  src={image9}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </React.Fragment>
  );
};

export default About;
